import { useCallback, useState } from 'react';

export function useSidebarCollapse({
  collapsed: controlledCollapsed,
  onCollapseChange,
}: {
  collapsed?: boolean;
  onCollapseChange?: (collapsed: boolean) => void;
}) {
  const isControlled = controlledCollapsed !== undefined;
  const [internalExpanded, setInternalExpanded] = useState(true);
  const isExpanded = isControlled ? !controlledCollapsed : internalExpanded;

  const toggleExpanded = useCallback(() => {
    const nextExpanded = !isExpanded;
    if (!isControlled) {
      setInternalExpanded(nextExpanded);
    }
    onCollapseChange?.(!nextExpanded);
  }, [isExpanded, isControlled, onCollapseChange]);

  const setIsExpanded = useCallback(
    (expanded: boolean) => {
      if (!isControlled) {
        setInternalExpanded(expanded);
      }
      if (!expanded) {
        onCollapseChange?.(true);
      }
    },
    [isControlled, onCollapseChange],
  );

  return { isExpanded, toggleExpanded, setIsExpanded };
}
