import type { PropsWithChildren } from 'react';
import React from 'react';

import { getShadowScrollStyles, Typography, useDesignSystemTheme } from '../../design-system';

export interface WizardStepContentWrapperProps {
  /**
   * Displayed in header of the step.
   *
   * ex)
   * `<FormattedMessage
   *   defaultMessage="STEP{stepIndex}"
   *   description="Wizard step number"
   *   values={{ stepIndex: stepIndex + 1 }}
   * />`
   */
  header?: React.ReactNode;

  /**
   * Title of the step
   */
  title: React.ReactNode;

  /**
   * Description of the step displayed below the step title
   */
  description: React.ReactNode;
  /**
   * Content to display between header and scrollable area, typically used for errors or alerts
   */
  alertContent?: React.ReactNode;

  /**
   * Where to render the description.
   * - 'header': render in the grey header area (default)
   * - 'content': render above children in the scrollable content area
   *
   * @default 'header'
   */
  descriptionPosition?: 'header' | 'content';
}

export function WizardStepContentWrapper({
  header,
  title,
  description,
  alertContent,
  descriptionPosition = 'header',
  children,
}: PropsWithChildren<WizardStepContentWrapperProps>) {
  const { theme } = useDesignSystemTheme();
  const hasHeader = Boolean(header);
  return (
    <div
      css={{
        display: 'flex',
        flexDirection: 'column',
        height: '100%',
      }}
    >
      <div
        style={{
          backgroundColor: theme.colors.backgroundSecondary,
          padding: hasHeader ? theme.spacing.lg : theme.spacing.md,
          display: 'flex',
          flexDirection: 'column',
          borderTopLeftRadius: theme.legacyBorders.borderRadiusLg,
          borderTopRightRadius: theme.legacyBorders.borderRadiusLg,
        }}
      >
        {hasHeader && (
          <Typography.Text size="sm" style={{ fontWeight: 500 }}>
            {header}
          </Typography.Text>
        )}
        <Typography.Title withoutMargins style={hasHeader ? { paddingTop: theme.spacing.lg } : undefined} level={3}>
          {title}
        </Typography.Title>
        {descriptionPosition === 'header' && <Typography.Text color="secondary">{description}</Typography.Text>}
      </div>
      {alertContent && (
        <div
          css={{
            padding: `${theme.spacing.lg}px ${theme.spacing.lg}px 0`,
          }}
        >
          {alertContent}
        </div>
      )}
      <div
        css={{
          display: 'flex',
          flexDirection: 'column',
          height: '100%',
          padding: `${theme.spacing.lg}px ${theme.spacing.lg}px 0`,
          overflowY: 'auto',
          ...getShadowScrollStyles(theme),
        }}
      >
        {descriptionPosition === 'content' && description && (
          <div css={{ paddingBottom: theme.spacing.md }}>
            <Typography.Text color="secondary">{description}</Typography.Text>
          </div>
        )}
        {children}
      </div>
    </div>
  );
}
